// ═══════════════════════════════════════════════════════════════════
// SYNTHOGRASIZER FACE GENERATOR - Enhanced & Polished
// Real-time face generation with getSynthVar() integration
// ═══════════════════════════════════════════════════════════════════

// ─── COLOR PALETTES ───────────────────────────────────────────────

const skinColors = {
  pale: '#FFE0BD',
  light: '#F1C27D',
  medium: '#E0AC69',
  tan: '#C68642',
  brown: '#8D5524',
  dark: '#5C3317'
};

const eyeColors = {
  brown: '#8B4513',
  hazel: '#8E7618',
  green: '#2E8B57',
  blue: '#4169E1',
  gray: '#708090',
  amber: '#FFBF00'
};

const hairColors = {
  black: '#1a1a1a',
  brown: '#654321',
  blonde: '#FAF0BE',
  red: '#8B0000',
  gray: '#808080',
  white: '#F5F5F5'
};

// ─── SETUP ────────────────────────────────────────────────────────

p.setup = function() {
  p.createCanvas(450, 500);
  p.smooth();
  p.print('✓ Face Generator Ready! Variables will update in real-time.');
  p.print('✓ Canvas: 450x500 (closer to 1:1 ratio)');
};

// ─── MAIN DRAW LOOP ───────────────────────────────────────────────

p.draw = function() {
  // Get all current face parameters from Synthograsizer
  const headShape = p.getSynthVar('head_shape') || 'oval';
  const skinTone = p.getSynthVar('skin_tone') || 'medium';
  const eyeColor = p.getSynthVar('eye_color') || 'brown';
  const eyeShape = p.getSynthVar('eye_shape') || 'almond';
  const eyebrowStyle = p.getSynthVar('eyebrow_style') || 'arched';
  const hairStyle = p.getSynthVar('hair_style') || 'short';
  const hairColor = p.getSynthVar('hair_color') || 'brown';
  const noseShape = p.getSynthVar('nose_shape') || 'straight';
  const mouthShape = p.getSynthVar('mouth_shape') || 'full';
  const earSize = p.getSynthVar('ear_size') || 'medium';
  const neckWidth = p.getSynthVar('neck_width') || 'average';
  const facialHair = p.getSynthVar('facial_hair') || 'none';
  const accessories = p.getSynthVar('accessories') || 'none';

  // Clean background with subtle gradient
  drawBackground();

  // Center point for face positioning (centered in canvas)
  const cx = 225;  // Horizontal center (450/2)
  const cy = 280;  // Vertical center adjusted for face proportions

  // Draw layers from back to front
  drawBody(cx, cy + 90, skinTone, neckWidth);
  drawNeck(cx, cy, skinTone, neckWidth);
  drawHead(cx, cy - 55, headShape, skinTone);
  drawEars(cx, cy - 55, earSize, skinTone);
  drawHair(cx, cy - 55, hairStyle, hairColor, headShape);
  drawEyes(cx, cy - 75, eyeShape, eyeColor);
  drawEyebrows(cx, cy - 95, eyebrowStyle);
  drawNose(cx, cy - 45, noseShape, skinTone);
  drawMouth(cx, cy - 15, mouthShape);

  // Conditional features
  if (facialHair !== 'none') {
    drawFacialHair(cx, cy, facialHair);
  }

  if (accessories !== 'none') {
    drawAccessories(cx, cy - 55, accessories);
  }
};

// ═══════════════════════════════════════════════════════════════════
// DRAWING FUNCTIONS
// ═══════════════════════════════════════════════════════════════════

// ─── BACKGROUND ───────────────────────────────────────────────────

function drawBackground() {
  // Subtle gradient background
  for (let y = 0; y < p.height; y++) {
    const inter = p.map(y, 0, p.height, 0, 1);
    const c = p.lerpColor(p.color(240, 245, 250), p.color(230, 235, 245), inter);
    p.stroke(c);
    p.line(0, y, p.width, y);
  }
  p.noStroke();
}

// ─── BODY (Unified torso, shoulders, and arms) ───────────────────

function drawBody(x, y, skinTone, neckWidth) {
  const widthMap = {
    'very-thin': 140,
    'thin': 150,
    'average': 160,
    'thick': 170,
    'wide': 180,
    'muscular': 190
  };

  const shoulderWidth = widthMap[neckWidth] || 160;
  const torsoWidth = shoulderWidth; // Match shoulder width exactly
  const shoulderRadius = 30; // Rounded shoulder curve

  // Calculate height to reach bottom of canvas
  const bodyHeight = p.height - y + 60; // Extends past bottom

  p.noStroke();

  // Main body shape
  p.fill(skinColors[skinTone]);

  // Draw torso extending to bottom
  p.rect(x - torsoWidth/2, y, torsoWidth, bodyHeight);

  // Rounded shoulders (ellipse on top)
  p.ellipse(x, y, shoulderWidth, shoulderRadius * 2);

  // Shoulder shading (darker on bottom of curve)
  p.fill(0, 0, 0, 20);
  p.arc(x, y, shoulderWidth, shoulderRadius * 2, 0, p.PI);

  // Torso side shading (adds depth)
  p.fill(0, 0, 0, 15);
  p.rect(x - torsoWidth/2, y, 12, bodyHeight);
  p.rect(x + torsoWidth/2 - 12, y, 12, bodyHeight);

  // Chest highlight (subtle)
  p.fill(255, 255, 255, 15);
  p.ellipse(x, y + 40, torsoWidth * 0.4, 50);

  // Collarbone shadow
  p.fill(0, 0, 0, 25);
  p.ellipse(x, y + 5, shoulderWidth * 0.6, 8);
}

// ─── NECK ─────────────────────────────────────────────────────────

function drawNeck(x, y, skinTone, neckWidth) {
  const widthMap = {
    'very-thin': 35,
    'thin': 40,
    'average': 45,
    'thick': 50,
    'wide': 55,
    'muscular': 60
  };

  const w = widthMap[neckWidth] || 45;
  const h = 50;

  // Simple neck - just a rectangle
  p.fill(skinColors[skinTone]);
  p.rect(x - w/2, y + 20, w, h);
}

// ─── HEAD ─────────────────────────────────────────────────────────

function drawHead(x, y, headShape, skinTone) {
  const skinColor = p.color(skinColors[skinTone]);

  // Head shadow
  p.fill(0, 0, 0, 20);
  switch(headShape) {
    case 'oval':
      p.ellipse(x + 3, y + 3, 180, 220);
      break;
    case 'round':
      p.circle(x + 3, y + 3, 200);
      break;
    case 'square':
      p.rect(x - 87, y - 97, 180, 200, 15);
      break;
    case 'heart':
      p.beginShape();
      p.vertex(x + 3, y + 103);
      p.bezierVertex(x - 87, y + 53, x - 87, y - 47, x + 3, y - 77);
      p.bezierVertex(x + 93, y - 47, x + 93, y + 53, x + 3, y + 103);
      p.endShape(p.CLOSE);
      break;
    case 'diamond':
      p.quad(x + 3, y - 107, x + 93, y + 3, x + 3, y + 113, x - 87, y + 3);
      break;
    case 'rectangular':
      p.rect(x - 77, y - 107, 160, 220, 10);
      break;
    default:
      p.ellipse(x + 3, y + 3, 180, 220);
  }

  // Main head
  p.fill(skinColor);
  switch(headShape) {
    case 'oval':
      p.ellipse(x, y, 180, 220);
      break;
    case 'round':
      p.circle(x, y, 200);
      break;
    case 'square':
      p.rect(x - 90, y - 100, 180, 200, 15);
      break;
    case 'heart':
      p.beginShape();
      p.vertex(x, y + 100);
      p.bezierVertex(x - 90, y + 50, x - 90, y - 50, x, y - 80);
      p.bezierVertex(x + 90, y - 50, x + 90, y + 50, x, y + 100);
      p.endShape(p.CLOSE);
      break;
    case 'diamond':
      p.quad(x, y - 110, x + 90, y, x, y + 110, x - 90, y);
      break;
    case 'rectangular':
      p.rect(x - 80, y - 110, 160, 220, 10);
      break;
    default:
      p.ellipse(x, y, 180, 220);
  }

  // Subtle highlight on forehead
  p.fill(255, 255, 255, 25);
  p.ellipse(x, y - 40, 80, 60);
}

// ─── EARS ─────────────────────────────────────────────────────────

function drawEars(x, y, earSize, skinTone) {
  const sizeMap = {
    'tiny': 15,
    'small': 20,
    'medium': 25,
    'large': 30,
    'prominent': 35,
    'hidden': 0
  };

  const size = sizeMap[earSize] || 25;

  if (size > 0) {
    // Ear shadows
    p.fill(0, 0, 0, 15);
    p.ellipse(x - 93, y + 2, size, size * 1.5);
    p.ellipse(x + 97, y + 2, size, size * 1.5);

    // Ears
    p.fill(skinColors[skinTone]);
    p.ellipse(x - 95, y, size, size * 1.5);
    p.ellipse(x + 95, y, size, size * 1.5);

    // Inner ear detail
    p.fill(0, 0, 0, 30);
    p.ellipse(x - 95, y, size * 0.4, size * 0.6);
    p.ellipse(x + 95, y, size * 0.4, size * 0.6);
  }
}

// ─── HAIR ─────────────────────────────────────────────────────────

function drawHair(x, y, hairStyle, hairColor, headShape) {
  p.fill(hairColors[hairColor]);

  if (hairStyle === 'bald') return;

  switch(hairStyle) {
    case 'short':
      p.arc(x, y - 50, 190, 140, p.PI, p.TWO_PI);
      break;
    case 'long':
      p.arc(x, y - 50, 190, 140, p.PI, p.TWO_PI);
      p.rect(x - 95, y - 50, 50, 150, 10);
      p.rect(x + 45, y - 50, 50, 150, 10);
      break;
    case 'wavy':
      for (let i = 0; i < 8; i++) {
        const angle = p.PI + (i * p.PI / 7);
        const px = x + p.cos(angle) * 95;
        const py = y - 50 + p.sin(angle) * 70 + p.sin(p.frameCount * 0.05 + i) * 5;
        p.circle(px, py, 25);
      }
      break;
    case 'curly':
      for (let i = 0; i < 12; i++) {
        const angle = p.PI + (i * p.PI / 11);
        const px = x + p.cos(angle) * 95;
        const py = y - 50 + p.sin(angle) * 70;
        p.circle(px, py, 20);
      }
      break;
    case 'straight':
      p.rect(x - 95, y - 120, 190, 70, 0, 0, 10, 10);
      break;
  }
}

// ─── EYES ─────────────────────────────────────────────────────────

function drawEyes(x, y, eyeShape, eyeColor) {
  const eyeWidth = 40;
  const eyeHeight = 30;
  const eyeSpacing = 60;

  // White of eyes
  p.fill(255);

  switch(eyeShape) {
    case 'almond':
      p.ellipse(x - eyeSpacing/2, y, eyeWidth, eyeHeight);
      p.ellipse(x + eyeSpacing/2, y, eyeWidth, eyeHeight);
      break;
    case 'round':
      p.circle(x - eyeSpacing/2, y, eyeWidth);
      p.circle(x + eyeSpacing/2, y, eyeWidth);
      break;
    case 'hooded':
      p.arc(x - eyeSpacing/2, y, eyeWidth, eyeHeight, 0, p.PI);
      p.arc(x + eyeSpacing/2, y, eyeWidth, eyeHeight, 0, p.PI);
      break;
    case 'narrow':
      p.ellipse(x - eyeSpacing/2, y, eyeWidth * 0.8, eyeHeight * 0.7);
      p.ellipse(x + eyeSpacing/2, y, eyeWidth * 0.8, eyeHeight * 0.7);
      break;
    case 'wide':
      p.ellipse(x - eyeSpacing/2, y, eyeWidth * 1.2, eyeHeight);
      p.ellipse(x + eyeSpacing/2, y, eyeWidth * 1.2, eyeHeight);
      break;
    case 'upturned':
      p.arc(x - eyeSpacing/2, y, eyeWidth, eyeHeight, -0.2, p.PI + 0.2);
      p.arc(x + eyeSpacing/2, y, eyeWidth, eyeHeight, -0.2, p.PI + 0.2);
      break;
  }

  // Iris
  p.fill(eyeColors[eyeColor]);
  p.circle(x - eyeSpacing/2, y, 20);
  p.circle(x + eyeSpacing/2, y, 20);

  // Pupil
  p.fill(0);
  p.circle(x - eyeSpacing/2, y, 10);
  p.circle(x + eyeSpacing/2, y, 10);

  // Highlight
  p.fill(255, 255, 255, 180);
  p.circle(x - eyeSpacing/2 - 3, y - 3, 4);
  p.circle(x + eyeSpacing/2 - 3, y - 3, 4);
}

// ─── EYEBROWS ────────────────────────────────────────────────────

function drawEyebrows(x, y, eyebrowStyle) {
  p.fill(60, 50, 40);
  p.noStroke();

  const eyebrowWidth = 45;
  const eyebrowHeight = 8;
  const eyebrowSpacing = 60;

  switch(eyebrowStyle) {
    case 'arched':
      p.arc(x - eyebrowSpacing/2, y, eyebrowWidth, eyebrowHeight * 2, p.PI, p.TWO_PI);
      p.arc(x + eyebrowSpacing/2, y, eyebrowWidth, eyebrowHeight * 2, p.PI, p.TWO_PI);
      break;
    case 'straight':
      p.rect(x - eyebrowSpacing/2 - eyebrowWidth/2, y, eyebrowWidth, eyebrowHeight, 2);
      p.rect(x + eyebrowSpacing/2 - eyebrowWidth/2, y, eyebrowWidth, eyebrowHeight, 2);
      break;
    case 'thick':
      p.rect(x - eyebrowSpacing/2 - eyebrowWidth/2, y, eyebrowWidth, eyebrowHeight * 1.5, 3);
      p.rect(x + eyebrowSpacing/2 - eyebrowWidth/2, y, eyebrowWidth, eyebrowHeight * 1.5, 3);
      break;
    case 'thin':
      p.rect(x - eyebrowSpacing/2 - eyebrowWidth/2, y, eyebrowWidth, eyebrowHeight * 0.5, 1);
      p.rect(x + eyebrowSpacing/2 - eyebrowWidth/2, y, eyebrowWidth, eyebrowHeight * 0.5, 1);
      break;
    case 'bushy':
      for (let i = 0; i < 8; i++) {
        p.circle(x - eyebrowSpacing/2 - eyebrowWidth/2 + i * 6, y + p.random(-2, 2), 6);
        p.circle(x + eyebrowSpacing/2 - eyebrowWidth/2 + i * 6, y + p.random(-2, 2), 6);
      }
      break;
    case 'angled':
      p.quad(
        x - eyebrowSpacing/2 - eyebrowWidth/2, y + 5,
        x - eyebrowSpacing/2 + eyebrowWidth/2, y - 5,
        x - eyebrowSpacing/2 + eyebrowWidth/2, y,
        x - eyebrowSpacing/2 - eyebrowWidth/2, y + 10
      );
      p.quad(
        x + eyebrowSpacing/2 - eyebrowWidth/2, y - 5,
        x + eyebrowSpacing/2 + eyebrowWidth/2, y + 5,
        x + eyebrowSpacing/2 + eyebrowWidth/2, y + 10,
        x + eyebrowSpacing/2 - eyebrowWidth/2, y
      );
      break;
  }
}

// ─── NOSE ─────────────────────────────────────────────────────────

function drawNose(x, y, noseShape, skinTone) {
  const noseColor = p.lerpColor(
    p.color(skinColors[skinTone]),
    p.color(0),
    0.1
  );
  p.fill(noseColor);

  switch(noseShape) {
    case 'straight':
      p.triangle(x - 8, y - 15, x + 8, y - 15, x, y + 20);
      break;
    case 'button':
      p.ellipse(x, y, 20, 25);
      break;
    case 'upturned':
      p.arc(x, y, 25, 30, 0, p.PI);
      break;
    case 'broad':
      p.triangle(x - 15, y - 15, x + 15, y - 15, x, y + 20);
      break;
    case 'narrow':
      p.triangle(x - 5, y - 15, x + 5, y - 15, x, y + 20);
      break;
    case 'long':
      p.triangle(x - 8, y - 25, x + 8, y - 25, x, y + 25);
      break;
  }

  // Nostrils
  p.fill(0, 0, 0, 80);
  p.circle(x - 6, y + 10, 4);
  p.circle(x + 6, y + 10, 4);
}

// ─── MOUTH ────────────────────────────────────────────────────────

function drawMouth(x, y, mouthShape) {
  p.fill(200, 80, 80);
  p.noStroke();

  switch(mouthShape) {
    case 'full':
      p.arc(x, y, 60, 30, 0, p.PI);
      break;
    case 'thin':
      p.arc(x, y, 50, 15, 0, p.PI);
      break;
    case 'wide':
      p.arc(x, y, 80, 30, 0, p.PI);
      break;
    case 'small':
      p.arc(x, y, 35, 20, 0, p.PI);
      break;
    case 'heart':
      p.beginShape();
      p.vertex(x - 20, y);
      p.bezierVertex(x - 20, y - 10, x - 10, y - 15, x, y - 10);
      p.bezierVertex(x + 10, y - 15, x + 20, y - 10, x + 20, y);
      p.bezierVertex(x + 20, y + 10, x, y + 15, x, y + 15);
      p.bezierVertex(x, y + 15, x - 20, y + 10, x - 20, y);
      p.endShape(p.CLOSE);
      break;
    case 'curved':
      p.arc(x, y - 5, 60, 40, 0, p.PI);
      break;
  }
}

// ─── FACIAL HAIR ──────────────────────────────────────────────────

function drawFacialHair(x, y, facialHair) {
  p.fill(60, 50, 40);

  switch(facialHair) {
    case 'mustache':
      p.arc(x - 15, y - 15, 30, 20, 0, p.PI);
      p.arc(x + 15, y - 15, 30, 20, 0, p.PI);
      break;
    case 'goatee':
      p.ellipse(x, y + 10, 25, 35);
      break;
    case 'full-beard':
      p.arc(x, y + 20, 120, 100, 0, p.PI);
      p.arc(x - 15, y - 15, 30, 20, 0, p.PI);
      p.arc(x + 15, y - 15, 30, 20, 0, p.PI);
      break;
    case 'stubble':
      for (let i = 0; i < 50; i++) {
        const px = x + p.random(-60, 60);
        const py = y + p.random(-20, 40);
        p.circle(px, py, 1.5);
      }
      break;
    case 'sideburns':
      p.rect(x - 95, y - 50, 15, 80, 5);
      p.rect(x + 80, y - 50, 15, 80, 5);
      break;
  }
}

// ─── ACCESSORIES ──────────────────────────────────────────────────

function drawAccessories(x, y, accessories) {
  if (accessories.includes('glasses') || accessories === 'glasses') {
    // Glasses
    p.noFill();
    p.stroke(40);
    p.strokeWeight(3);
    p.circle(x - 30, y - 20, 45);
    p.circle(x + 30, y - 20, 45);
    p.line(x - 7, y - 20, x + 7, y - 20);
    p.noStroke();
  }

  if (accessories.includes('sunglasses') || accessories === 'sunglasses') {
    // Sunglasses
    p.fill(20, 20, 20, 180);
    p.ellipse(x - 30, y - 20, 50, 35);
    p.ellipse(x + 30, y - 20, 50, 35);
    p.stroke(40);
    p.strokeWeight(3);
    p.line(x - 5, y - 20, x + 5, y - 20);
    p.noStroke();
  }

  if (accessories.includes('earrings') || accessories === 'earrings') {
    // Earrings
    p.fill(255, 215, 0);
    p.circle(x - 95, y + 15, 10);
    p.circle(x + 95, y + 15, 10);
  }

  if (accessories.includes('hat') || accessories === 'hat') {
    // Hat
    p.fill(80, 60, 40);
    p.rect(x - 70, y - 120, 140, 15, 5);
    p.arc(x, y - 120, 100, 60, p.PI, p.TWO_PI);
  }
}

